import { Component, signal, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { NavbarComponent } from '../../shared/components/navbar/navbar.component';
import { HeroComponent } from '../../shared/components/hero/hero.component';
import { AboutComponent } from '../../shared/components/about/about.component';
import { ExperienceComponent } from '../../shared/components/experience/experience.component';
import { SkillsComponent } from '../../shared/components/skills/skills.component';
import { AchievementsComponent } from '../../shared/components/achievements/achievements.component';
import { EducationComponent } from '../../shared/components/education/education.component';
import { HobbiesComponent } from '../../shared/components/hobbies/hobbies.component';
import { FooterComponent } from '../../shared/components/footer/footer.component';
import { ChatbotComponent } from '../../shared/components/chatbot/chatbot.component';
import { ContactModalComponent } from '../../shared/components/contact-modal/contact-modal.component';

@Component({
  selector: 'app-home',
  standalone: true,
  imports: [
    CommonModule,
    NavbarComponent,
    HeroComponent,
    AboutComponent,
    ExperienceComponent,
    SkillsComponent,
    AchievementsComponent,
    EducationComponent,
    HobbiesComponent,
    FooterComponent,
    ChatbotComponent,
    ContactModalComponent,
  ],
  template: `
    <app-navbar (openContact)="contactOpen.set(true)" />

    <main>
      <app-hero (contact)="contactOpen.set(true)" />
      <app-about />
      <app-experience />
      <app-skills />
      <app-achievements />
      <app-education />
      <app-hobbies />
    </main>

    <app-footer />
    <app-chatbot />
    <app-contact-modal [isOpen]="contactOpen()" (close)="contactOpen.set(false)" />
  `,
})
export class HomeComponent implements OnInit {
  contactOpen = signal(false);

  ngOnInit() {
    this.initScrollReveal();
  }

  private initScrollReveal() {
    const observer = new IntersectionObserver(
      (entries) => entries.forEach(e => {
        if (e.isIntersecting) {
          e.target.classList.add('visible');
          observer.unobserve(e.target);
        }
      }),
      { threshold: 0.1, rootMargin: '0px 0px -60px 0px' }
    );

    setTimeout(() => {
      document.querySelectorAll('.reveal, .reveal-left, .reveal-right').forEach(el => {
        observer.observe(el);
      });
    }, 200);
  }
}
