import { Component, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { PortfolioService } from '../../../core/services/portfolio.service';

@Component({
  selector: 'app-skills',
  standalone: true,
  imports: [CommonModule],
  template: `
    <section id="skills" class="relative py-24 overflow-hidden">
      <div class="absolute inset-0" style="background: linear-gradient(180deg, #071828 0%, #0B2035 100%);"></div>

      <div class="relative z-10 max-w-6xl mx-auto px-6">

        <!-- Header -->
        <div class="reveal text-center mb-16">
          <div class="section-tag mx-auto mb-4">Expertise</div>
          <h2 class="font-display text-4xl lg:text-5xl font-bold text-white mb-4">Skills & Competencies</h2>
          <div class="section-divider w-24 mx-auto"></div>
        </div>

        <!-- Core Competencies -->
        <div class="reveal reveal-delay-1 mb-12">
          <div class="font-mono text-xs text-teal-DEFAULT/60 tracking-widest uppercase mb-4">Core Competencies</div>
          <div class="flex flex-wrap gap-3">
            @for (skill of skills(); track skill) {
              <span class="skill-chip">{{ skill }}</span>
            }
          </div>
        </div>

        <!-- Technical Skills -->
        <div class="reveal reveal-delay-2">
          <div class="font-mono text-xs text-teal-DEFAULT/60 tracking-widest uppercase mb-4">Technical Skills</div>
          <div class="grid sm:grid-cols-2 lg:grid-cols-3 gap-4">
            @for (group of techGroups(); track group.title) {
              <div class="glass-card rounded-2xl p-5 border border-teal-DEFAULT/10 hover:border-teal-DEFAULT/25 transition-all duration-300 group">
                <!-- Group header -->
                <div class="flex items-center gap-2 mb-4">
                  <div class="w-2 h-2 rounded-full" [style.background]="group.color"></div>
                  <span class="font-mono text-xs tracking-widest uppercase" [style.color]="group.color">{{ group.title }}</span>
                </div>

                <!-- Tags -->
                <div class="flex flex-wrap gap-2">
                  @for (tag of group.items; track tag) {
                    <span class="tech-tag hover:border-teal-DEFAULT/30 transition-colors cursor-default">{{ tag }}</span>
                  }
                </div>
              </div>
            }
          </div>
        </div>

        <!-- Proficiency radar / visual -->
        <div class="reveal reveal-delay-3 mt-12">
          <div class="glass-card rounded-2xl p-6 border border-teal-DEFAULT/10">
            <div class="font-mono text-xs text-teal-DEFAULT/60 tracking-widest uppercase mb-5">Proficiency Overview</div>
            <div class="grid sm:grid-cols-2 lg:grid-cols-3 gap-4">
              @for (prof of proficiency; track prof.label) {
                <div>
                  <div class="flex justify-between items-center mb-1.5">
                    <span class="text-sm text-white/60 font-sans">{{ prof.label }}</span>
                    <span class="font-mono text-xs text-teal-DEFAULT">{{ prof.value }}%</span>
                  </div>
                  <div class="h-1.5 rounded-full overflow-hidden" style="background: rgba(255,255,255,0.06);">
                    <div class="h-full rounded-full bg-brand-grad-h transition-all duration-1000 bar-animate"
                         [style.width]="prof.value + '%'"></div>
                  </div>
                </div>
              }
            </div>
          </div>
        </div>

      </div>
    </section>
  `,
})
export class SkillsComponent {
  private portfolioService = inject(PortfolioService);
  skills = this.portfolioService.skills;

  techGroups() {
    const tech = this.portfolioService.tech();
    return [
      { title: 'Cloud & Tools', items: tech.cloud, color: '#09AFE9' },
      { title: 'AI & GenAI',   items: tech.ai,    color: '#18D1C1' },
      { title: 'Development',  items: tech.dev,   color: '#2AF599' },
    ];
  }

  proficiency = [
    { label: 'Programme & Project Delivery', value: 95 },
    { label: 'Agile / Scrum / SAFe',         value: 92 },
    { label: 'Stakeholder Management',        value: 90 },
    { label: 'GenAI & AI Tooling',            value: 88 },
    { label: 'AWS Cloud Architecture',        value: 80 },
    { label: 'Budget & Financial Governance', value: 85 },
  ];
}
