import { Component, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { PortfolioService } from '../../../core/services/portfolio.service';

@Component({
  selector: 'app-education',
  standalone: true,
  imports: [CommonModule],
  template: `
    <section id="education" class="relative py-24 overflow-hidden">
      <div class="absolute inset-0" style="background: linear-gradient(180deg, #071828 0%, #0B2035 100%);"></div>

      <div class="relative z-10 max-w-6xl mx-auto px-6">

        <!-- Header -->
        <div class="reveal text-center mb-16">
          <div class="section-tag mx-auto mb-4">Learning</div>
          <h2 class="font-display text-4xl lg:text-5xl font-bold text-white mb-4">Education & Certifications</h2>
          <div class="section-divider w-24 mx-auto"></div>
        </div>

        <div class="grid lg:grid-cols-2 gap-8">

          <!-- Education -->
          <div class="reveal reveal-delay-1 space-y-4">
            <div class="font-mono text-xs text-teal-DEFAULT/60 tracking-widest uppercase mb-4">Academic Background</div>

            @for (edu of degrees(); track edu.degree) {
              <div class="glass-card rounded-2xl p-6 border border-teal-DEFAULT/10 hover:border-teal-DEFAULT/25 transition-all group">
                <div class="flex items-start gap-4">
                  <div class="w-10 h-10 rounded-xl flex items-center justify-center flex-shrink-0"
                       style="background: linear-gradient(135deg, rgba(9,175,233,0.15), rgba(42,245,153,0.15)); border: 1px solid rgba(24,209,193,0.2);">
                    <span class="text-lg">{{ edu.icon }}</span>
                  </div>
                  <div>
                    <div class="font-sans font-semibold text-white text-sm mb-0.5">{{ edu.degree }}</div>
                    <div class="font-sans text-sm font-medium" style="color: #18D1C1;">{{ edu.institution }}</div>
                    @if (edu.note) {
                      <div class="font-mono text-xs text-white/35 mt-1 italic">{{ edu.note }}</div>
                    }
                  </div>
                </div>
              </div>
            }
          </div>

          <!-- Certifications -->
          <div class="reveal reveal-delay-2">
            <div class="font-mono text-xs text-teal-DEFAULT/60 tracking-widest uppercase mb-4">Certifications</div>

            <div class="glass-card rounded-2xl border border-teal-DEFAULT/10 overflow-hidden">
              @for (cert of certs(); track cert; let last = $last) {
                <div class="flex items-start gap-4 p-5"
                     [class.border-b]="!last"
                     style="border-color: rgba(24,209,193,0.08);">
                  <div class="flex-shrink-0 mt-0.5">
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#2AF599" stroke-width="2">
                      <path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/>
                    </svg>
                  </div>
                  <div>
                    <div class="text-sm text-white/70 font-sans leading-snug">
                      {{ cert.split('·')[0].trim() }}
                    </div>
                    @if (cert.includes('·')) {
                      <div class="font-mono text-xs text-white/30 mt-0.5 flex items-center gap-2">
                        {{ cert.split('·')[1].trim() }}
                        @if (cert.toLowerCase().includes('active')) {
                          <span class="px-2 py-0.5 rounded-full text-xs" style="background: rgba(42,245,153,0.1); color: #2AF599; border: 1px solid rgba(42,245,153,0.2);">Active</span>
                        }
                        @if (cert.toLowerCase().includes('progress')) {
                          <span class="px-2 py-0.5 rounded-full text-xs" style="background: rgba(9,175,233,0.1); color: #09AFE9; border: 1px solid rgba(9,175,233,0.2);">In Progress</span>
                        }
                      </div>
                    }
                  </div>
                </div>
              }
            </div>
          </div>

        </div>
      </div>
    </section>
  `,
})
export class EducationComponent {
  private portfolioService = inject(PortfolioService);

  degrees() {
    const edu = this.portfolioService.edu();
    return [
      {
        degree: edu.deg1,
        institution: edu.inst1,
        icon: '🎓',
        note: "India's premier management institution"
      },
      {
        degree: edu.deg2,
        institution: edu.inst2,
        icon: '💻',
        note: 'Engineering foundation in computer science'
      }
    ];
  }

  certs() {
    return this.portfolioService.edu().certs;
  }
}
