import { Injectable, signal } from '@angular/core';
import { ChatMessage } from '../models/portfolio.model';

const SYSTEM_PROMPT = `You are "Ananth's AI Assistant" — an intelligent, professional, and conversational AI embedded in Ananth Machiraju's personal portfolio. You represent Ananth accurately and help recruiters, hiring managers, and collaborators understand his profile deeply.

CRITICAL FACTS:
- Notice Period: 90 to 60 days (negotiable)
- Total Experience: 10 years
- Current Location: Bengaluru, Karnataka, India
- Work Mode: Open to On-site, Hybrid, and Remote — including international relocation
- Current Status: Employed at TCS, actively open to the right opportunity
- Contact: ananth.machiraju@outlook.com | +91 7416261622

PROFILE SUMMARY:
Ananth is a Project Manager at TCS working on NEST Pensions UK. 10 years of IT experience across financial services (UK pensions), Nordic logistics (PostNord via Capgemini), and healthcare analytics (Medvensys/Pareto). IIM Bangalore graduate, AWS Certified Solutions Architect, SAFe® 5 Practitioner, PMP candidate. Early GenAI adopter with proven productivity gains.

KEY ACHIEVEMENTS:
- Zero critical release failures across 3+ years of CAB-managed deployments at NEST UK
- 40%+ production incident reduction at PostNord through automation
- ~30% documentation efficiency gain via GenAI embedding at TCS
- 49/75 NCQA certification measures at Pareto Healthcare

SKILLS: Programme Delivery, Agile/Scrum/SAFe, Stakeholder Management, IT Governance, CAB & Release Planning, Risk Management, Budget Governance, Digital Transformation, GenAI, Cross-Functional Leadership, JIRA, AWS, Node.js, Angular, Oracle/SQL

EDUCATION: GMITE at IIM Bengaluru | B.Tech CSE at JNTU Kakinada
CERTIFICATIONS: AWS SA-Associate (Active), PMP (In Progress), SAFe® 5 SP (Active), PGP Product Management

Respond warmly, professionally, and concisely. Use markdown for formatting. After answering, suggest 1-2 relevant follow-up questions. Never fabricate information.`;

@Injectable({ providedIn: 'root' })
export class ChatService {
  messages = signal<ChatMessage[]>([]);
  isTyping = signal(false);
  isOpen = signal(false);

  private history: { role: string; content: string }[] = [];

  toggle() { this.isOpen.update(v => !v); }
  open()   { this.isOpen.set(true); }
  close()  { this.isOpen.set(false); }

  async send(userText: string): Promise<void> {
    if (!userText.trim() || this.isTyping()) return;

    const userMsg: ChatMessage = { role: 'user', content: userText, timestamp: new Date() };
    this.messages.update(m => [...m, userMsg]);
    this.history.push({ role: 'user', content: userText });
    if (this.history.length > 32) this.history = this.history.slice(-32);

    this.isTyping.set(true);

    await new Promise(r => setTimeout(r, 400 + Math.random() * 400));

    try {
      const response = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'anthropic-dangerous-request-source': 'user-iframe'
        },
        body: JSON.stringify({
          model: 'claude-sonnet-4-20250514',
          max_tokens: 1200,
          system: SYSTEM_PROMPT,
          messages: this.history.map(m => ({ role: m.role, content: m.content }))
        })
      });
      const data = await response.json();
      const reply = data?.content?.[0]?.text || this.localAnswer(userText);
      this.addBot(reply);
    } catch {
      this.addBot(this.localAnswer(userText));
    }
  }

  private addBot(content: string) {
    this.isTyping.set(false);
    const botMsg: ChatMessage = { role: 'assistant', content, timestamp: new Date() };
    this.messages.update(m => [...m, botMsg]);
    this.history.push({ role: 'assistant', content });
    if (this.history.length > 32) this.history = this.history.slice(-32);
  }

  clear() {
    this.messages.set([]);
    this.history = [];
  }

  private localAnswer(q: string): string {
    const t = q.toLowerCase();
    if (/notice.?period|availability|when.?can|join|start|available/.test(t))
      return "Ananth's **notice period is 90 to 60 days**, negotiable depending on the opportunity. For urgent positions, a direct conversation is recommended.";
    if (/current.?role|working.?now|tcs|tata|nest/.test(t))
      return "Ananth is currently a **Project Manager at TCS**, delivering for **NEST Pensions UK**.\n\n**Highlights:**\n- Zero critical release failures across 3+ years\n- Built the Low Friction Changes (LFC) initiative from scratch\n- Led Employer 2.0 — NEST's largest ever platform overhaul\n- ~30% documentation efficiency gain via GenAI";
    if (/achiev|highlight|impact|result|success|metric|record/.test(t))
      return "**Key achievements:**\n\n- **Zero** critical release failures — 3+ years at NEST Pensions UK\n- **40%+** incident reduction at PostNord through automation\n- **~30%** documentation efficiency gain via GenAI at TCS\n- **49/75** NCQA measures certified at Pareto Healthcare\n- **Employer 2.0** — NEST's largest platform overhaul, delivered on time";
    if (/certif|aws|pmp|safe|credential/.test(t))
      return "**Certifications:**\n\n- AWS Certified Solutions Architect – Associate *(Active)*\n- SAFe® 5 Practitioner *(Active)*\n- PMP – PMI *(In Progress)*\n- PGP in Product Management — Accredian\n- Agile & Product Development Specialisation";
    if (/educat|iim|jntu|degree|university/.test(t))
      return "**Education:**\n\n- **GMITE – General Management (Executive)** | IIM Bengaluru\n- **B.Tech – Computer Science Engineering** | JNTU Kakinada";
    if (/contact|email|phone|linkedin|reach/.test(t))
      return "📧 **Email:** ananth.machiraju@outlook.com\n📞 **Phone:** +91 7416261622\n🔗 **LinkedIn:** linkedin.com/in/saiananthmachiraju\n\nOr use the **Contact Me** button on this page!";
    if (/location|where|based|relocat|remote|hybrid/.test(t))
      return "Ananth is based in **Bengaluru, India**. He is open to:\n- **Remote** roles globally\n- **Hybrid** arrangements\n- **On-site** with relocation\n- **International** opportunities";
    if (/why.?hire|unique|stand.?out|differenti|value/.test(t))
      return "**What makes Ananth unique:**\n\n1. **Rare hybrid** — developer background + PM leadership\n2. **Zero-failure track record** — 3+ years regulated delivery\n3. **GenAI pioneer** — formalised AI-assisted PM workflows\n4. **Multi-industry** — FinTech, Logistics, Healthcare\n5. **IIM Bengaluru** executive education";
    if (/genai|ai.?tool|claude|chatgpt|copilot|llm/.test(t))
      return "Ananth is a **GenAI practitioner**:\n\n- Embedded Claude, ChatGPT, and Copilot into TCS delivery workflows\n- Achieved **~30% documentation efficiency gain**\n- Developed structured prompt engineering workflows\n- Among the **first TCS teams** to formalise AI-assisted PM";
    if (/salary|ctc|compensation|pay/.test(t))
      return "Compensation is best discussed directly with Ananth at **ananth.machiraju@outlook.com** or **+91 7416261622**.";
    return "Great question! I'm trained on Ananth's full profile. Ask me about:\n\n- **Experience** & career history\n- **Notice period** & availability\n- **Skills** (technical & PM)\n- **Certifications** & education\n- **Achievements** & key wins\n- **Contact** details";
  }
}
