import { Component, inject, signal, HostListener, Output, EventEmitter } from '@angular/core';
import { RouterLink, RouterLinkActive } from '@angular/router';
import { CommonModule } from '@angular/common';
import { ThemeService } from '../../../core/services/theme.service';

@Component({
  selector: 'app-navbar',
  standalone: true,
  imports: [RouterLink, RouterLinkActive, CommonModule],
  template: `
    <nav [class]="'fixed top-0 left-0 right-0 z-50 transition-all duration-300 ' +
                   (scrolled() ? 'glass-strong border-b shadow-nav' : '')"
         style="border-color: rgba(24,209,193,0.1);">

      <div class="max-w-6xl mx-auto px-6 flex items-center justify-between h-16">

        <!-- Brand -->
        <a routerLink="/" class="flex items-center gap-3 group">
          <div class="w-9 h-9 flex-shrink-0" style="filter: drop-shadow(0 0 8px rgba(24,209,193,0.4));">
            <svg viewBox="0 0 80 80" xmlns="http://www.w3.org/2000/svg">
              <defs>
                <linearGradient id="navGrad" x1="0%" y1="0%" x2="100%" y2="100%">
                  <stop offset="0%" stop-color="#2AF599"/>
                  <stop offset="100%" stop-color="#09AFE9"/>
                </linearGradient>
              </defs>
              <circle cx="40" cy="40" r="39" fill="#071828" stroke="#18D1C1" stroke-width="1.5"/>
              <circle cx="40" cy="40" r="33" fill="none" stroke="#2AF599" stroke-width="0.5" stroke-dasharray="3 4"/>
              <path d="M18 58 L30 22 L40 46 M22 46 H36" stroke="url(#navGrad)" stroke-width="4" stroke-linecap="round" stroke-linejoin="round" fill="none"/>
              <path d="M40 58 L40 22 L52 42 L64 22 L64 58" stroke="#FEFEFE" stroke-width="3.5" stroke-linecap="round" stroke-linejoin="round" fill="none"/>
              <circle cx="40" cy="40" r="3" fill="#18D1C1"/>
            </svg>
          </div>
          <div class="hidden sm:block">
            <div class="font-display text-sm font-semibold text-white leading-none">Ananth Machiraju</div>
            <div class="font-mono text-xs text-teal-DEFAULT/60 tracking-wider mt-0.5">Project Manager</div>
          </div>
        </a>

        <!-- Desktop Nav Links -->
        <div class="hidden md:flex items-center gap-1">
          @for (link of navLinks; track link.anchor) {
            <a [href]="link.anchor"
               class="px-4 py-2 rounded-lg font-sans text-sm font-medium transition-all duration-200 text-white/50 hover:text-white hover:bg-white/5"
               (click)="scrollTo($event, link.anchor)">
              {{ link.label }}
            </a>
          }
        </div>

        <!-- Right Actions -->
        <div class="flex items-center gap-2">
          <!-- Theme Toggle -->
          <button (click)="themeService.toggle()"
                  class="w-9 h-9 rounded-full flex items-center justify-center transition-all duration-200 flex-shrink-0"
                  style="color:rgba(255,255,255,0.5);background:transparent;border:none;cursor:pointer;"
                  title="Toggle theme">
            @if (themeService.theme() === 'dark') {
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                <circle cx="12" cy="12" r="5"/><line x1="12" y1="1" x2="12" y2="3"/>
                <line x1="12" y1="21" x2="12" y2="23"/><line x1="4.22" y1="4.22" x2="5.64" y2="5.64"/>
                <line x1="18.36" y1="18.36" x2="19.78" y2="19.78"/><line x1="1" y1="12" x2="3" y2="12"/>
                <line x1="21" y1="12" x2="23" y2="12"/><line x1="4.22" y1="19.78" x2="5.64" y2="18.36"/>
                <line x1="18.36" y1="5.64" x2="19.78" y2="4.22"/>
              </svg>
            } @else {
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                <path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"/>
              </svg>
            }
          </button>

          <a routerLink="/dashboard" class="hidden sm:inline-flex btn-ghost text-xs">
            ⚙ Admin
          </a>

          <button class="hidden sm:inline-flex btn-brand text-xs px-4 py-2" (click)="openContact.emit()">
            ✉ Contact Me
          </button>

          <!-- Mobile hamburger -->
          <button class="md:hidden w-9 h-9 flex items-center justify-center rounded-lg transition-all duration-200 flex-shrink-0"
                  style="color:rgba(255,255,255,0.5);background:transparent;border:none;cursor:pointer;"
                  (click)="toggleMenu()">
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
              @if (!menuOpen()) {
                <line x1="3" y1="6" x2="21" y2="6"/><line x1="3" y1="12" x2="21" y2="12"/><line x1="3" y1="18" x2="21" y2="18"/>
              } @else {
                <line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/>
              }
            </svg>
          </button>
        </div>
      </div>

      <!-- Mobile Menu -->
      @if (menuOpen()) {
        <div class="md:hidden glass-strong border-t border-teal-DEFAULT/10">
          <div class="px-6 py-4 flex flex-col gap-1">
            @for (link of navLinks; track link.anchor) {
              <a [href]="link.anchor"
                 class="px-4 py-3 rounded-lg text-sm font-medium text-white/60 hover:text-white hover:bg-white/5 transition-colors"
                 (click)="scrollTo($event, link.anchor); menuOpen.set(false)">
                {{ link.label }}
              </a>
            }
            <div class="mt-3 pt-3 border-t border-white/5 flex flex-col gap-2">
              <button class="btn-brand w-full justify-center py-3" (click)="openContact.emit(); menuOpen.set(false)">
                ✉ Contact Me
              </button>
              <a routerLink="/dashboard" class="btn-ghost w-full justify-center py-3 text-sm" (click)="menuOpen.set(false)">
                ⚙ Admin Dashboard
              </a>
            </div>
          </div>
        </div>
      }
    </nav>
  `,
})
export class NavbarComponent {
  themeService = inject(ThemeService);
  scrolled = signal(false);
  menuOpen = signal(false);
  @Output() openContact = new EventEmitter<void>();

  navLinks = [
    { label: 'About',        anchor: '#about' },
    { label: 'Experience',   anchor: '#experience' },
    { label: 'Skills',       anchor: '#skills' },
    { label: 'Achievements', anchor: '#achievements' },
    { label: 'Education',    anchor: '#education' },
    { label: 'Hobbies',      anchor: '#hobbies' },
  ];

  @HostListener('window:scroll')
  onScroll() {
    this.scrolled.set(window.scrollY > 48);
  }

  toggleMenu() {
    this.menuOpen.update(v => !v);
  }

  scrollTo(e: Event, anchor: string) {
    e.preventDefault();
    const el = document.querySelector(anchor);
    if (el) el.scrollIntoView({ behavior: 'smooth', block: 'start' });
  }
}
