import { Component, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { PortfolioService } from '../../../core/services/portfolio.service';

@Component({
  selector: 'app-experience',
  standalone: true,
  imports: [CommonModule],
  template: `
    <section id="experience" class="relative py-24 overflow-hidden">
      <div class="absolute inset-0" style="background: #071828;"></div>

      <!-- Background accent -->
      <div class="absolute top-0 left-0 right-0 h-px" style="background: linear-gradient(90deg,transparent,rgba(24,209,193,0.3),transparent);"></div>

      <div class="relative z-10 max-w-6xl mx-auto px-6">

        <!-- Header -->
        <div class="reveal text-center mb-16">
          <div class="section-tag mx-auto mb-4">Career</div>
          <h2 class="font-display text-4xl lg:text-5xl font-bold text-white mb-4">Professional Experience</h2>
          <div class="section-divider w-24 mx-auto"></div>
        </div>

        <!-- Timeline -->
        <div class="relative">
          <!-- Center line (desktop) -->
          <div class="hidden lg:block timeline-line"></div>

          <div class="space-y-12">
            @for (exp of experience(); track exp.company; let i = $index) {
              <div class="reveal" [class]="'reveal-delay-' + (i + 1)">
                <div class="lg:grid lg:grid-cols-2 lg:gap-12 items-center"
                     [class.direction-reverse]="i % 2 !== 0">

                  <!-- Content card -->
                  <div [class]="i % 2 !== 0 ? 'lg:col-start-2' : ''">
                    <div class="glass-card rounded-2xl border transition-all duration-300 hover:shadow-card-hover group relative overflow-hidden"
                         [style.border-color]="'rgba(' + hexToRgb(exp.color || '#18D1C1') + ',0.2)'"
                         (mouseenter)="active.set(i)"
                         (mouseleave)="active.set(-1)">

                      <!-- Top gradient bar -->
                      <div class="h-1 w-full rounded-t-2xl"
                           [style.background]="'linear-gradient(90deg,' + (exp.color || '#09AFE9') + ',' + getNext(exp.color || '#09AFE9') + ')'">
                      </div>

                      <!-- Holographic hover effect -->
                      <div class="absolute inset-0 opacity-0 group-hover:opacity-100 transition-opacity duration-500 pointer-events-none rounded-2xl"
                           [style.background]="'radial-gradient(circle at 50% 50%, rgba(' + hexToRgb(exp.color || '#18D1C1') + ',0.04), transparent 70%)'">
                      </div>

                      <div class="p-6 lg:p-8">
                        <!-- Header -->
                        <div class="flex items-start justify-between gap-4 mb-4">
                          <div>
                            <div class="font-sans font-semibold text-lg text-white mb-1">{{ exp.role }}</div>
                            <div class="font-sans font-medium text-sm mb-1" [style.color]="exp.color || '#18D1C1'">{{ exp.company }}</div>
                            <div class="font-sans text-xs text-white/40 italic">{{ exp.client }}</div>
                          </div>
                          <span class="flex-shrink-0 font-mono text-xs px-3 py-1.5 rounded-lg"
                                style="background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); color: rgba(255,255,255,0.4);">
                            {{ exp.period }}
                          </span>
                        </div>

                        <!-- Tags -->
                        @if (exp.tags?.length) {
                          <div class="flex flex-wrap gap-1.5 mb-4">
                            @for (tag of exp.tags; track tag) {
                              <span class="tech-tag text-xs">{{ tag }}</span>
                            }
                          </div>
                        }

                        <!-- Bullets -->
                        <ul class="space-y-3">
                          @for (bullet of exp.bullets; track bullet) {
                            <li class="flex gap-3 text-sm text-white/60 leading-relaxed">
                              <span class="flex-shrink-0 mt-1 text-xs" [style.color]="exp.color || '#18D1C1'">↳</span>
                              {{ bullet }}
                            </li>
                          }
                        </ul>
                      </div>
                    </div>
                  </div>

                  <!-- Timeline node (desktop only) -->
                  <div class="hidden lg:flex items-center justify-center"
                       [class]="i % 2 !== 0 ? 'lg:col-start-1 lg:row-start-1' : ''">
                    <div class="relative z-10 flex flex-col items-center gap-2">
                      <div class="w-4 h-4 rounded-full border-2 transition-all duration-300"
                           [style.background]="active() === i ? (exp.color || '#18D1C1') : 'transparent'"
                           [style.border-color]="exp.color || '#18D1C1'"
                           [style.box-shadow]="active() === i ? '0 0 16px ' + (exp.color || '#18D1C1') : 'none'">
                      </div>
                      <div class="font-mono text-xs text-white/30 text-center leading-tight max-w-24">
                        {{ exp.period.split('–')[0].trim() }}
                      </div>
                    </div>
                  </div>

                </div>
              </div>
            }
          </div>
        </div>
      </div>
    </section>
  `,
})
export class ExperienceComponent {
  private portfolioService = inject(PortfolioService);
  experience = this.portfolioService.experience;
  active = signal(-1);

  hexToRgb(hex: string): string {
    const r = parseInt(hex.slice(1, 3), 16);
    const g = parseInt(hex.slice(3, 5), 16);
    const b = parseInt(hex.slice(5, 7), 16);
    return `${r},${g},${b}`;
  }

  getNext(color: string): string {
    const map: Record<string, string> = {
      '#09AFE9': '#18D1C1',
      '#18D1C1': '#2AF599',
      '#2AF599': '#09AFE9',
    };
    return map[color] || '#2AF599';
  }
}
