import { Component, inject, signal, ViewChild, ElementRef, AfterViewChecked } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ChatService } from '../../../core/services/chat.service';
import { ChatMessage } from '../../../core/models/portfolio.model';

@Component({
  selector: 'app-chatbot',
  standalone: true,
  imports: [CommonModule, FormsModule],
  template: `
    <!-- FAB Button -->
    <button class="chat-fab"
            [class.open]="chatService.isOpen()"
            (click)="chatService.toggle()"
            title="Chat with Ananth's AI">
      <svg class="chat-fab-icon" width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
        <path d="M21 15a2 2 0 01-2 2H7l-4 4V5a2 2 0 012-2h14a2 2 0 012 2z"/>
      </svg>
      <svg class="chat-fab-close" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
        <line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/>
      </svg>

      <!-- Unread badge -->
      @if (!chatService.isOpen() && chatService.messages().length === 0) {
        <div class="chat-badge show">1</div>
      }
    </button>

    <!-- Chat Window -->
    <div class="chat-window" [class.open]="chatService.isOpen()">

      <!-- Clear confirm toast -->
      <div class="chat-clear-toast" [class.show]="showClearConfirm()">
        <span>Clear this conversation?</span>
        <div class="flex gap-2">
          <button class="chat-clear-yes" (click)="confirmClear()">Clear</button>
          <button class="chat-clear-no" (click)="showClearConfirm.set(false)">Keep</button>
        </div>
      </div>

      <!-- Header -->
      <div class="chat-header">
        <div class="chat-avatar">🤖</div>
        <div class="chat-header-info">
          <div class="chat-header-name">Ananth's AI Assistant</div>
          <div class="chat-header-sub">Powered by <span>Claude</span> · Knows everything</div>
        </div>
        <div class="chat-header-actions">
          <button class="chat-hdr-btn" title="Clear chat" (click)="showClearConfirm.set(true)">
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14H6L5 6"/><path d="M10 11v6M14 11v6"/><path d="M9 6V4h6v2"/></svg>
          </button>
          <button class="chat-hdr-btn" title="Close" (click)="chatService.close()">
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
          </button>
        </div>
      </div>

      <!-- Quick chips -->
      <div class="chat-chips-wrap">
        <div class="chat-chips-label">Quick topics</div>
        <div class="chat-chips">
          @for (chip of chips; track chip.label) {
            <button class="chat-chip" (click)="sendChip(chip.q)">{{ chip.label }}</button>
          }
        </div>
      </div>

      <!-- Messages -->
      <div class="chat-messages" #messagesEl>
        @if (chatService.messages().length === 0) {
          <div class="chat-msg bot">
            <div class="chat-msg-avatar">🤖</div>
            <div>
              <div class="chat-bubble">
                <p style="margin:0">Hi there! 👋 I'm Ananth's AI Assistant — I know everything about his profile, experience, skills, and availability.</p>
                <p style="margin:6px 0 0">Feel free to ask me anything, or pick a topic above!</p>
              </div>
              <div class="chat-ts">{{ now() }}</div>
            </div>
          </div>
        }

        @for (msg of chatService.messages(); track $index) {
          <div class="chat-msg" [class.user]="msg.role === 'user'" [class.bot]="msg.role === 'assistant'">
            @if (msg.role === 'assistant') {
              <div class="chat-msg-avatar">🤖</div>
            } @else {
              <div class="chat-msg-avatar" style="background:linear-gradient(135deg,#071828,#1A3A50);color:#2AF599;font-size:0.6rem;font-weight:700;letter-spacing:0.5px;">YOU</div>
            }
            <div class="chat-msg-col">
              <div class="chat-bubble" [innerHTML]="formatMessage(msg.content)"></div>
              <div class="chat-ts">{{ formatTime(msg.timestamp) }}</div>
            </div>
          </div>
        }

        <!-- Typing indicator -->
        @if (chatService.isTyping()) {
          <div class="chat-typing show">
            <div class="chat-msg-avatar">🤖</div>
            <div class="typing-bubble">
              <div class="typing-dot"></div>
              <div class="typing-dot"></div>
              <div class="typing-dot"></div>
            </div>
          </div>
        }
      </div>

      <!-- Input area -->
      <div class="chat-input-area">
        <textarea class="chat-input" #inputEl
                  [(ngModel)]="inputText"
                  placeholder="Ask about Ananth's experience, skills, availability…"
                  rows="1"
                  (keydown.enter)="onEnter($event)"
                  (input)="autoResize($event)">
        </textarea>
        <button class="chat-send-btn" [disabled]="!inputText.trim() || chatService.isTyping()" (click)="send()">
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/></svg>
        </button>
      </div>
      <div class="chat-input-hint">Shift+Enter for new line · Enter to send</div>
    </div>
  `,
})
export class ChatbotComponent implements AfterViewChecked {
  chatService = inject(ChatService);
  @ViewChild('messagesEl') messagesEl!: ElementRef<HTMLDivElement>;
  @ViewChild('inputEl') inputEl!: ElementRef<HTMLTextAreaElement>;

  inputText = '';
  showClearConfirm = signal(false);
  private prevLen = 0;

  chips = [
    { label: '🗓 Notice Period',  q: 'What is the notice period?' },
    { label: '💼 Current Role',   q: 'What is the current role and responsibilities?' },
    { label: '⭐ Achievements',   q: 'What are the biggest career achievements with numbers?' },
    { label: '🛠 Tech Stack',     q: 'What are the technical skills and tools?' },
    { label: '🤝 Why Hire?',      q: 'Why should we hire Ananth? What makes him unique?' },
    { label: '📞 Contact',        q: 'How can I contact Ananth directly?' },
  ];

  now() {
    const d = new Date();
    return d.getHours().toString().padStart(2,'0') + ':' + d.getMinutes().toString().padStart(2,'0');
  }

  formatTime(d: Date): string {
    return d.getHours().toString().padStart(2,'0') + ':' + d.getMinutes().toString().padStart(2,'0');
  }

  formatMessage(text: string): string {
    let s = text
      .replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
      .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
      .replace(/^[-•] (.+)$/gm, '<li>$1</li>')
      .replace(/(<li>.*?<\/li>)+/gs, m => `<ul>${m}</ul>`)
      .replace(/\n\n/g, '</p><p>')
      .replace(/\n/g, '<br>');
    return `<p>${s}</p>`;
  }

  sendChip(q: string) {
    this.inputText = q;
    this.send();
  }

  async send() {
    const text = this.inputText.trim();
    if (!text) return;
    this.inputText = '';
    if (this.inputEl) { this.inputEl.nativeElement.style.height = ''; }
    await this.chatService.send(text);
  }

  onEnter(e: Event) {
    const ke = e as KeyboardEvent;
    if (!ke.shiftKey) { e.preventDefault(); this.send(); }
  }

  autoResize(e: Event) {
    const el = e.target as HTMLTextAreaElement;
    el.style.height = '';
    el.style.height = Math.min(el.scrollHeight, 120) + 'px';
  }

  confirmClear() {
    this.chatService.clear();
    this.showClearConfirm.set(false);
  }

  ngAfterViewChecked() {
    const len = this.chatService.messages().length;
    if (len !== this.prevLen && this.messagesEl) {
      this.prevLen = len;
      const el = this.messagesEl.nativeElement;
      setTimeout(() => { el.scrollTop = el.scrollHeight; }, 60);
    }
  }
}
