import { Component, Input, Output, EventEmitter, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';

@Component({
  selector: 'app-contact-modal',
  standalone: true,
  imports: [CommonModule, FormsModule],
  template: `
    @if (isOpen) {
      <div class="fixed inset-0 z-[1000] flex items-center justify-center p-4"
           style="background: rgba(7,24,40,0.8); backdrop-filter: blur(8px);"
           (click)="onOverlayClick($event)">

        <div class="relative w-full max-w-xl max-h-[92vh] overflow-y-auto rounded-2xl flex flex-col"
             style="background: #0B2035; border: 1px solid rgba(24,209,193,0.15); box-shadow: 0 20px 60px rgba(7,24,40,0.5), 0 0 0 1px rgba(24,209,193,0.08);"
             (click)="$event.stopPropagation()">

          <!-- Header -->
          <div class="flex items-center justify-between p-6 border-b flex-shrink-0"
               style="border-color: rgba(24,209,193,0.08); background: linear-gradient(135deg, rgba(9,175,233,0.05), rgba(42,245,153,0.05));">
            <div class="flex items-center gap-3">
              <div class="w-10 h-10 rounded-xl flex items-center justify-center" style="background: linear-gradient(135deg,#09AFE9,#2AF599);">
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#071828" stroke-width="2.5">
                  <path d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z"/>
                  <polyline points="22,6 12,13 2,6"/>
                </svg>
              </div>
              <div>
                <div class="font-display text-lg font-semibold text-white">Get In Touch</div>
                <div class="font-mono text-xs text-white/35">Send a message to Ananth</div>
              </div>
            </div>
            <button class="w-8 h-8 rounded-full flex items-center justify-center text-white/40 hover:text-white hover:bg-white/5 transition-all"
                    (click)="close.emit()">
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
            </button>
          </div>

          <!-- Body -->
          <div class="p-6 space-y-4 flex-1">

            <!-- Toast -->
            @if (toast()) {
              <div class="p-4 rounded-xl text-sm font-sans"
                   [style]="toast()!.type === 'success'
                     ? 'background: rgba(21,168,106,0.1); border: 1px solid rgba(21,168,106,0.2); color: #2AF599;'
                     : 'background: rgba(224,62,82,0.1); border: 1px solid rgba(224,62,82,0.2); color: #E03E52;'">
                {{ toast()!.msg }}
              </div>
            }

            <div class="grid grid-cols-2 gap-4">
              <div class="space-y-1.5">
                <label class="font-mono text-xs text-white/40 uppercase tracking-wider">Name *</label>
                <input type="text" [(ngModel)]="form.name" placeholder="Your full name"
                       class="w-full px-4 py-2.5 rounded-xl text-sm font-sans text-white placeholder:text-white/20 outline-none transition-all"
                       style="background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08);"
                       (focus)="$any($event.target).style.borderColor='rgba(24,209,193,0.4)'"
                       (blur)="$any($event.target).style.borderColor='rgba(255,255,255,0.08)'">
              </div>
              <div class="space-y-1.5">
                <label class="font-mono text-xs text-white/40 uppercase tracking-wider">Email *</label>
                <input type="email" [(ngModel)]="form.email" placeholder="your@email.com"
                       class="w-full px-4 py-2.5 rounded-xl text-sm font-sans text-white placeholder:text-white/20 outline-none transition-all"
                       style="background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08);"
                       (focus)="$any($event.target).style.borderColor='rgba(24,209,193,0.4)'"
                       (blur)="$any($event.target).style.borderColor='rgba(255,255,255,0.08)'">
              </div>
            </div>

            <div class="space-y-1.5">
              <label class="font-mono text-xs text-white/40 uppercase tracking-wider">Mobile <span class="text-white/20 normal-case tracking-normal">(optional)</span></label>
              <div class="flex rounded-xl overflow-hidden" style="border: 1px solid rgba(255,255,255,0.08);">
                <span class="px-3 flex items-center font-mono text-xs text-white/30 flex-shrink-0" style="background: rgba(255,255,255,0.03); border-right: 1px solid rgba(255,255,255,0.08);">+91</span>
                <input type="tel" [(ngModel)]="form.mobile" placeholder="10-digit number" maxlength="10"
                       class="flex-1 px-3 py-2.5 text-sm font-sans text-white placeholder:text-white/20 outline-none"
                       style="background: transparent;">
              </div>
            </div>

            <div class="space-y-1.5">
              <label class="font-mono text-xs text-white/40 uppercase tracking-wider">Message *</label>
              <textarea [(ngModel)]="form.message" placeholder="Your message..." rows="4"
                        class="w-full px-4 py-2.5 rounded-xl text-sm font-sans text-white placeholder:text-white/20 outline-none resize-none transition-all"
                        style="background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08);"
                        (focus)="$any($event.target).style.borderColor='rgba(24,209,193,0.4)'"
                        (blur)="$any($event.target).style.borderColor='rgba(255,255,255,0.08)'">
              </textarea>
            </div>

          </div>

          <!-- Footer -->
          <div class="flex justify-end gap-3 p-6 border-t flex-shrink-0" style="border-color: rgba(24,209,193,0.08); background: rgba(255,255,255,0.02);">
            <button class="btn-ghost" (click)="close.emit()">Cancel</button>
            <button class="btn-brand" [disabled]="sending()" (click)="submit()">
              @if (sending()) {
                <svg class="animate-spin" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><path d="M21 12a9 9 0 1 1-6.219-8.56"/></svg>
                Sending…
              } @else {
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/></svg>
                Send Message
              }
            </button>
          </div>
        </div>
      </div>
    }
  `,
})
export class ContactModalComponent {
  @Input() isOpen = false;
  @Output() close = new EventEmitter<void>();

  form = { name: '', email: '', mobile: '', message: '' };
  sending = signal(false);
  toast = signal<{ type: 'success' | 'error'; msg: string } | null>(null);

  onOverlayClick(e: MouseEvent) {
    if (e.target === e.currentTarget) this.close.emit();
  }

  async submit() {
    if (!this.form.name.trim() || !this.form.email.trim() || !this.form.message.trim()) {
      this.toast.set({ type: 'error', msg: 'Please fill in Name, Email, and Message.' });
      return;
    }
    this.sending.set(true);
    this.toast.set(null);

    await new Promise(r => setTimeout(r, 800));

    const subject = encodeURIComponent(`Portfolio Enquiry from ${this.form.name}`);
    const body = encodeURIComponent(
      `Name: ${this.form.name}\nEmail: ${this.form.email}\nMobile: ${this.form.mobile || 'Not provided'}\n\nMessage:\n${this.form.message}`
    );
    const mailtoUrl = `mailto:ananth.machiraju@outlook.com?subject=${subject}&body=${body}`;

    this.sending.set(false);
    this.toast.set({ type: 'success', msg: '✓ Opening your email client… Message ready to send!' });
    window.location.href = mailtoUrl;

    setTimeout(() => {
      this.form = { name: '', email: '', mobile: '', message: '' };
      this.toast.set(null);
      this.close.emit();
    }, 2000);
  }
}
